import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import {
  Info,
  CheckCircle2,
  AlertTriangle,
  XCircle,
  X,
} from "lucide-react"

import { cn } from "@/lib/utils"
import "./alert.css"

/* ------------------------------------------------------------------ */
/*  Variant icons                                                      */
/* ------------------------------------------------------------------ */

const variantIcons = {
  brand: Info,
  success: CheckCircle2,
  warning: AlertTriangle,
  danger: XCircle,
} as const

/* ------------------------------------------------------------------ */
/*  CVA                                                                */
/* ------------------------------------------------------------------ */

const alertVariants = cva(
  "flex items-start gap-[var(--layout-gap-md)] rounded-[var(--layout-radius-lg)] p-[var(--layout-padding-lg)] [&_svg]:shrink-0 [&_svg]:size-4",
  {
    variants: {
      variant: {
        brand: "alert-brand",
        success: "alert-success",
        warning: "alert-warning",
        danger: "alert-danger",
      },
    },
    defaultVariants: {
      variant: "brand",
    },
  }
)

/* ------------------------------------------------------------------ */
/*  Alert                                                              */
/* ------------------------------------------------------------------ */

function Alert({
  className,
  variant = "brand",
  icon,
  action,
  actionPlacement = "bottom",
  onDismiss,
  children,
  ...props
}: React.ComponentProps<"div"> &
  VariantProps<typeof alertVariants> & {
    icon?: React.ReactNode | null
    action?: React.ReactNode
    actionPlacement?: "bottom" | "right"
    onDismiss?: () => void
  }) {
  const showIcon = icon !== null
  const IconComponent = variant ? variantIcons[variant] : variantIcons.brand

  return (
    <div
      data-slot="alert"
      role="alert"
      aria-live="polite"
      className={cn(alertVariants({ variant, className }))}
      {...props}
    >
      {showIcon && (
        <span className="alert-icon mt-0.5 shrink-0" aria-hidden="true">
          {icon !== undefined ? icon : <IconComponent />}
        </span>
      )}

      <div className="flex min-w-0 flex-1 flex-col gap-[var(--layout-gap-xs)]">
        {children}
        {action && actionPlacement === "bottom" && (
          <div className="mt-[var(--layout-gap-sm)]">{action}</div>
        )}
      </div>

      {action && actionPlacement === "right" && (
        <div className="shrink-0 self-center">{action}</div>
      )}

      {onDismiss && (
        <button
          type="button"
          className="alert-dismiss shrink-0"
          aria-label="Dismiss"
          onClick={onDismiss}
        >
          <X aria-hidden="true" />
        </button>
      )}
    </div>
  )
}

/* ------------------------------------------------------------------ */
/*  AlertTitle                                                         */
/* ------------------------------------------------------------------ */

function AlertTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="alert-title"
      className={cn("text-content-note font-accent [color:var(--text-base-strong)]", className)}
      {...props}
    />
  )
}

/* ------------------------------------------------------------------ */
/*  AlertDescription                                                   */
/* ------------------------------------------------------------------ */

function AlertDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="alert-description"
      className={cn("text-content-note [color:var(--text-base-bolder)]", className)}
      {...props}
    />
  )
}

export { Alert, AlertTitle, AlertDescription, alertVariants }

/* ================================================================
 * ALERT — Variant Styles
 * Structure (flex, padding, gap, radius) lives in alert.tsx via cva.
 * Theming (colors, borders, accent) lives here via tokens.
 * ================================================================ */

/* --------------------------------
 * Variant tokens
 * Each variant sets scoped custom properties.
 * -------------------------------- */

.alert-brand {
  --alert-bg: var(--background-brand-lighter-default);
  --alert-accent: var(--border-brand-strong);
  --alert-icon: var(--icon-brand-bolder);
}

.alert-success {
  --alert-bg: var(--background-success-lighter-default);
  --alert-accent: var(--border-success-strong);
  --alert-icon: var(--icon-success-bolder);
}

.alert-warning {
  --alert-bg: var(--background-warning-lighter-default);
  --alert-accent: var(--border-warning-strong);
  --alert-icon: var(--icon-warning-bolder);
}

.alert-danger {
  --alert-bg: var(--background-danger-lighter-default);
  --alert-accent: var(--border-danger-strong);
  --alert-icon: var(--icon-danger-bolder);
}

/* --------------------------------
 * Base — applied to all variants
 * -------------------------------- */

.alert-brand,
.alert-success,
.alert-warning,
.alert-danger {
  background: var(--alert-bg);
  border-left: 4px solid var(--alert-accent);
}

/* --------------------------------
 * Icon color — separate from text
 * -------------------------------- */

.alert-icon {
  color: var(--alert-icon);
}

/* --------------------------------
 * Dismiss button
 * -------------------------------- */

.alert-dismiss {
  display: flex;
  align-items: center;
  justify-content: center;
  width: var(--layout-size-md);
  height: var(--layout-size-md);
  color: var(--text-base-moderate);
  background: transparent;
  border: none;
  cursor: pointer;
}

.alert-dismiss:hover {
  color: var(--text-base-strong);
}

.alert-dismiss:focus-visible {
  outline: 2px solid var(--border-selected);
  outline-offset: 2px;
}
